app counterApp {
  wasp: {
    version: "^0.21.1"
  },
  title: "counter-app",
  head: [
    "<link rel='icon' href='/favicon.ico' />",
  ]
}

route RootRoute { path: "/", to: MainPage }
page MainPage {
  component: import { MainPage } from "@src/MainPage"
}

query getCounter {
  fn: import { getCounter } from "@src/queries",
  entities: [Counter]
}

action increment {
  fn: import { increment } from "@src/actions",
  entities: [Counter]
}

action decrement {
  fn: import { decrement } from "@src/actions",
  entities: [Counter]
}

import { type GetCounter } from 'wasp/server/operations';

export const getCounter: GetCounter<void, { id: number; count: number }> = async (args, context) => {
  let counter = await context.entities.Counter.findFirst();
  if (!counter) {
    counter = await context.entities.Counter.create({
      data: {
        count: 0
      }
    });
  }
  return counter;
};
import { type Increment, type Decrement } from 'wasp/server/operations';

export const increment: Increment<void, { id: number; count: number }> = async (args, context) => {
  let counter = await context.entities.Counter.findFirst();
  if (!counter) {
    counter = await context.entities.Counter.create({
      data: { count: 0 }
    });
  }
  return context.entities.Counter.update({
    where: { id: counter.id },
    data: { count: counter.count + 1 }
  });
};

export const decrement: Decrement<void, { id: number; count: number }> = async (args, context) => {
  let counter = await context.entities.Counter.findFirst();
  if (!counter) {
    counter = await context.entities.Counter.create({
      data: { count: 0 }
    });
  }
  return context.entities.Counter.update({
    where: { id: counter.id },
    data: { count: counter.count - 1 }
  });
};

datasource db {
  provider = "sqlite"
  // Wasp requires that the url is set to the DATABASE_URL environment variable.
  url      = env("DATABASE_URL")
}

// Wasp requires the `prisma-client-js` generator to be present.
generator client {
  provider = "prisma-client-js"
}

model Counter {
  id    Int @id @default(autoincrement())
  count Int @default(0)
}

import { useQuery, useAction, getCounter, increment, decrement } from 'wasp/client/operations';

export const MainPage = () => {
  const { data: counter, isLoading, error } = useQuery(getCounter);
  const incrementAction = useAction(increment);
  const decrementAction = useAction(decrement);

  if (isLoading) return <div>Loading...</div>;
  if (error) return <div>Error: {error.message}</div>;

  return (
    <div style={{ textAlign: 'center', marginTop: '50px' }}>
      <h1>Wasp Counter</h1>
      <div style={{ fontSize: '2rem', margin: '20px' }}>
        Count: {counter?.count}
      </div>
      <div>
        <button 
          onClick={() => decrementAction(undefined)} 
          style={{ padding: '10px 20px', fontSize: '1rem', marginRight: '10px' }}
        >
          Decrement
        </button>
        <button 
          onClick={() => incrementAction(undefined)} 
          style={{ padding: '10px 20px', fontSize: '1rem' }}
        >
          Increment
        </button>
      </div>
    </div>
  );
};

import express from 'express'

import { HttpError } from 'wasp/server'
import indexRouter from './routes/index.js'

// TODO: Consider extracting most of this logic into createApp(routes, path) function so that
//   it can be used in unit tests to test each route individually.

const app = express()

// NOTE: Middleware are installed on a per-router or per-route basis.

app.use('/', indexRouter)

// Custom error handler.
app.use((err, _req, res, next) => {
  // As by expressjs documentation, when the headers have already
  // been sent to the client, we must delegate to the default error handler.
  if (res.headersSent) { return next(err) }

  if (err instanceof HttpError) {
    return res.status(err.statusCode).json({ message: err.message, data: err.data })
  }

  // This forwards the error to the default express error handler.
  // As described by expressjs documentation, the default error handler sets response status
  // to err.status or err.statusCode if it is 4xx or 5xx, and if not, sets it to 500.
  // It won't add any more info to it if server is running in production, which is exactly what we want,
  // we want to share as little info as possible when error happens in production, for security reasons,
  // so they will get only status code if set, or 500 if not, no extra info.
  // In development it will also share the error stack though, which is useful.
  // If the user wants to put more information about the error into the response, they should use HttpError.
  return next(err)
})

export default app

import express from 'express'
import operations from './operations/index.js'
import { globalMiddlewareConfigForExpress } from '../middleware/index.js'
import { config } from 'wasp/server'
import { makeWrongPortPage } from '../views/wrong-port.js'


const router = express.Router()
const middleware = globalMiddlewareConfigForExpress()

router.get('/', middleware,
    function (_req, res) {
      const data = {
        appName: "counterApp",
        frontendUrl: config.frontendUrl
      };
      const wrongPortPage = makeWrongPortPage(data);
      res.status(200).type('html').send(wrongPortPage);
    }
)

router.use('/operations', middleware, operations)

export default router

